parameters.jsCode:
const summaryRows = $('Get Week Menu Summary').all().map(i => i.json);

const targetWeekStart =
  $('Resolve Admin Menu Week').item.json.target_week_start ||
  $('Code in JavaScript').item.json.value1;

const chatId =
  $('Code in JavaScript').item.json.admin_chat_id ||
  $('Telegram Trigger').item.json.callback_query?.message?.chat?.id ||
  $('Telegram Trigger').item.json.message?.chat?.id;

const allDays = [
  'شنبه',
  'یکشنبه',
  'دوشنبه',
  'سه شنبه',
  'چهارشنبه',
  'پنج شنبه',
];

const menuMap = {};

for (const item of summaryRows) {
  if (!item.day_of_week) continue;

 menuMap[item.day_of_week] = {
  food1: item.food1,
  food2: item.food2,
  food3: item.food3,
};
}

// اول دکمه‌های روزها را بساز
const rows = allDays.map((day) => {
  const existing = menuMap[day];

  let text = day;

if (existing) {
  const cleanFood = (value) => {
    if (value === null || value === undefined) return null;

    const text = String(value).trim();

    if (!text) return null;
    if (text.toLowerCase() === 'null') return null;
    if (text.toLowerCase() === 'undefined') return null;
    if (text === '—') return null;

    return text;
  };

  const foodsText = [
    cleanFood(existing.food1),
    cleanFood(existing.food2),
    cleanFood(existing.food3),
  ]
    .filter(Boolean)
    .join(' - ');

  text += foodsText ? ` ✅ (${foodsText})` : ' ✅';
} else {
  text += ' ➕';
} 

  return [
    {
      text,
      callback_data: `add_day_menu|${targetWeekStart}|${day}`,
    },
  ];
});

// بعد از ساخته شدن rows، دکمه ارسال اعلان را اضافه کن
rows.push([
  {
    text: '📣 ارسال اطلاع‌رسانی برنامه غذایی هفته',
    callback_data: `publish_week_menu|${targetWeekStart}`,
  },
]);

// دکمه برگشت
rows.push([
  {
    text: '🔙 بازگشت',
    callback_data: 'back_admin_menu|1',
  },
]);

let text = '🍽 مدیریت برنامه غذایی هفته\n\n';
text += `📅 هفته: ${targetWeekStart}\n\n`;
text += 'روز موردنظر را برای افزودن یا ویرایش غذا انتخاب کنید:';

return [
  {
    json: {
      chat_id: chatId,
      text,
      reply_markup: {
        inline_keyboard: rows,
      },
    },
  },
];

