parameters.jsCode:
const status = $('Code in JavaScript').item.json.arg1;

const statusMap = {
  pending: '🟡 کاربران تایید نشده',
  approved: '🟢 کاربران تایید شده',
  blocked: '🔴 کاربران مسدود شده',
  rejected: '🔴 کاربران رد شده'
};

if (!items.length) {
  return [
    {
      json: {
        text: `${statusMap[status] || '👥 لیست کاربران'}\n\nهیچ موردی یافت نشد.`
      }
    }
  ];
}

const lines = items.map((item, index) => {
  const u = item.json;
  const fullName = `${u.first_name || ''} ${u.last_name || ''}`.trim() || '—';
  const username = u.username ? '@' + u.username : '—';
  const access = u.access_level || '—';

  return `${index + 1}) 👤 ${fullName}
🔹 ${username}
🆔 ${u.telegram_user_id}
🔐 سطح دسترسی: ${access}
📌 وضعیت: ${u.status}`;
});

return [
  {
    json: {
      text: `${statusMap[status] || '👥 لیست کاربران'}\n\n${lines.join('\n\n')}`
    }
  }
];

const rows = items.map(i => i.json).filter(r => r.day_of_week);

const weekStartJalali =
  $('Code in JavaScript4').item.json.target_week_start_jalali || 'نامشخص';

const chatId =
  $('Code in JavaScript').item.json.admin_chat_id ||
  $('Telegram Trigger').item.json.callback_query?.message?.chat?.id ||
  $('Telegram Trigger').item.json.message?.chat?.id;

const MAX_MESSAGE_LENGTH = 3500;

const dayOrder = [
  'شنبه',
  'یکشنبه',
  'دوشنبه',
  'سه شنبه',
  'سه‌شنبه',
  'چهارشنبه',
  'پنج شنبه',
  'پنج‌شنبه',
];

function normalizeDay(value) {
  return String(value || '').replace(/‌/g, ' ').trim();
}

function cleanText(value, fallback = '—') {
  const text = String(value || '').trim();
  return text || fallback;
}

function cleanName(row) {
  const firstName = cleanText(row.first_name, '');
  const lastName = cleanText(row.last_name, '');

  const fullName = `${firstName} ${lastName}`.trim();

  if (fullName) return fullName;
  if (row.username) return `@${row.username}`;

  return 'بدون نام';
}

function cleanUsername(row) {
  const username = String(row.username || '').trim();

  if (!username) return 'بدون یوزرنیم';

  return username.startsWith('@') ? username : `@${username}`;
}

function cleanPortion(row) {
  return cleanText(row.portion_label, 'پرس کامل');
}

function cleanFood(row) {
  return cleanText(row.food, 'غذا ثبت نشده');
}

function buildRowLine(row, index) {
  return [
    `${index + 1}. 👤 ${cleanName(row)}`,
    `   🔹 ${cleanUsername(row)}`,
    `   🍽 ${cleanFood(row)} - ${cleanPortion(row)}`,
  ].join('\n');
}

if (!rows.length) {
  return [
    {
      json: {
        chat_id: chatId,
        text:
`📊 گزارش کامل رزروهای هفته

هفته شروع‌شونده از: ${weekStartJalali}

هیچ رزروی برای این هفته ثبت نشده است.`,
      },
    },
  ];
}

const grouped = {};

for (const row of rows) {
  const day = normalizeDay(row.day_of_week) || 'نامشخص';

  if (!grouped[day]) {
    grouped[day] = [];
  }

  grouped[day].push(row);
}

const sortedDays = Object.keys(grouped).sort((a, b) => {
  const ai = dayOrder.findIndex(d => normalizeDay(d) === normalizeDay(a));
  const bi = dayOrder.findIndex(d => normalizeDay(d) === normalizeDay(b));

  return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
});

const output = [];

let partNumber = 1;
let currentText =
`📊 گزارش کامل رزروهای هفته
📅 هفته شروع‌شونده از: ${weekStartJalali}
🧾 تعداد کل رزروها: ${rows.length}

`;

function pushCurrentText() {
  const text = currentText.trim();

  if (!text) return;

  output.push({
    json: {
      chat_id: chatId,
      text,
      part: partNumber,
    },
  });

  partNumber += 1;
  currentText = '';
}

function appendBlock(block) {
  if (!block.trim()) return;

  if ((currentText + '\n' + block).length > MAX_MESSAGE_LENGTH) {
    pushCurrentText();
    currentText =
`📊 ادامه گزارش رزروهای هفته
📅 هفته شروع‌شونده از: ${weekStartJalali}

`;
  }

  currentText += block + '\n\n';
}

for (const day of sortedDays) {
  const dayRows = grouped[day] || [];

  let dayHeader = `🗓 ${day} — ${dayRows.length} رزرو\n`;

  appendBlock(dayHeader);

  dayRows.forEach((row, index) => {
    const block = buildRowLine(row, index);
    appendBlock(block);
  });
}

pushCurrentText();

const totalParts = output.length;

return output.map((item, index) => {
  return {
    json: {
      ...item.json,
      text:
`${item.json.text}

━━━━━━━━━━━━━━
صفحه ${index + 1} از ${totalParts}`,
      total_parts: totalParts,
    },
  };
});

const TEHRAN_TZ = "Asia/Tehran";
const CUTOFF_HOUR = 19;
const CUTOFF_MINUTE = 0;

function getTehranNowParts(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: TEHRAN_TZ,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hourCycle: "h23",
  }).formatToParts(date);

  const map = {};
  for (const part of parts) {
    map[part.type] = part.value;
  }

  return {
    year: Number(map.year),
    month: Number(map.month),
    day: Number(map.day),
    hour: Number(map.hour),
    minute: Number(map.minute),
    second: Number(map.second),
  };
}

function addDaysUtc(date, days) {
  const result = new Date(date);
  result.setUTCDate(result.getUTCDate() + days);
  return result;
}

function toIsoDate(date) {
  return date.toISOString().slice(0, 10);
}

function toPersianDigits(value) {
  return String(value).replace(/\d/g, (digit) => "۰۱۲۳۴۵۶۷۸۹"[digit]);
}

function toJalali(date) {
  const formatted = new Intl.DateTimeFormat("fa-IR-u-ca-persian", {
    timeZone: TEHRAN_TZ,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(date);

  return toPersianDigits(formatted);
}

const nowParts = getTehranNowParts();

const todayTehranAsUtcDate = new Date(Date.UTC(
  nowParts.year,
  nowParts.month - 1,
  nowParts.day
));

// JS day:
// Sunday=0, Monday=1, Tuesday=2, Wednesday=3, Thursday=4, Friday=5, Saturday=6
const jsDay = todayTehranAsUtcDate.getUTCDay();

// شنبه شروع هفته است
const daysSinceSaturday = (jsDay - 6 + 7) % 7;

const currentWeekStart = addDaysUtc(todayTehranAsUtcDate, -daysSinceSaturday);
const nextWeekStart = addDaysUtc(currentWeekStart, 7);

// منطق انتخاب هفته گزارش:
// شنبه تا پنجشنبه قبل از ۱۹:۰۰ => هفته جاری
// پنجشنبه از ۱۹:۰۰ به بعد و کل جمعه => هفته بعد
let targetWeekStart = currentWeekStart;
let reportWeekMode = "current_week";

const isThursdayAfterCutoff =
  jsDay === 4 &&
  (
    nowParts.hour > CUTOFF_HOUR ||
    (nowParts.hour === CUTOFF_HOUR && nowParts.minute >= CUTOFF_MINUTE)
  );

const isFriday = jsDay === 5;

if (isThursdayAfterCutoff || isFriday) {
  targetWeekStart = nextWeekStart;
  reportWeekMode = "next_week";
}

return [
  {
    json: {
      target_week_start: toIsoDate(targetWeekStart),
      target_week_start_jalali: toJalali(targetWeekStart),
      current_week_start: toIsoDate(currentWeekStart),
      current_week_start_jalali: toJalali(currentWeekStart),
      next_week_start: toIsoDate(nextWeekStart),
      next_week_start_jalali: toJalali(nextWeekStart),
      report_week_mode: reportWeekMode,
      tehran_weekday_js: jsDay,
      tehran_hour: nowParts.hour,
      tehran_minute: nowParts.minute,
    },
  },
];

const items = $input.all();
const rawRows = items.map((item) => item.json || {});

const rows = rawRows.filter((row) => row.day_of_week && row.food);
const firstRow = rawRows[0] || {};

const DAY_ORDER = {
  "شنبه": 1,
  "یکشنبه": 2,
  "دوشنبه": 3,
  "سه شنبه": 4,
  "سه‌شنبه": 4,
  "چهارشنبه": 5,
  "پنج شنبه": 6,
  "پنج‌شنبه": 6,
};

function normalizeDay(value) {
  return String(value || "").replace(/‌/g, " ").trim();
}

function toNumber(value) {
  const numberValue = Number(value);
  return Number.isFinite(numberValue) ? numberValue : 0;
}

function formatQty(value) {
  const numberValue = toNumber(value);

  if (Number.isInteger(numberValue)) {
    return String(numberValue);
  }

  return String(Math.round(numberValue * 100) / 100);
}

function toPersianDigits(value) {
  return String(value).replace(/\d/g, (digit) => "۰۱۲۳۴۵۶۷۸۹"[digit]);
}

function addDaysToIsoDate(isoDate, days) {
  if (!isoDate) return null;

  const date = new Date(`${isoDate}T00:00:00+03:30`);
  date.setDate(date.getDate() + days);

  return date.toISOString().slice(0, 10);
}

function toJalaliDate(isoDate) {
  if (!isoDate) return "";

  try {
    const date = new Date(`${isoDate}T00:00:00+03:30`);

    return new Intl.DateTimeFormat("fa-IR-u-ca-persian", {
      timeZone: "Asia/Tehran",
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
    }).format(date);
  } catch (error) {
    return isoDate;
  }
}

const targetWeekStart = firstRow.target_week_start
  ? String(firstRow.target_week_start).slice(0, 10)
  : "";

const targetWeekEnd = addDaysToIsoDate(targetWeekStart, 5);

const targetWeekStartJalali = toJalaliDate(targetWeekStart);
const targetWeekEndJalali = toJalaliDate(targetWeekEnd);

const totalReservations = toNumber(firstRow.total_reservations);
const weeklyUniqueUsers = toNumber(firstRow.weekly_unique_users);
const weeklyTotalPortionQty = toNumber(firstRow.weekly_total_portion_qty);

const rowsByDay = new Map();

for (const row of rows) {
  const day = normalizeDay(row.day_of_week);

  if (!rowsByDay.has(day)) {
    rowsByDay.set(day, []);
  }

  rowsByDay.get(day).push({
    day_of_week: day,
    food: row.food,
    portion_label: row.portion_label || "پرس کامل",
    people_count: toNumber(row.people_count),
    total_portion_qty: toNumber(row.total_portion_qty),
  });
}

const sortedDays = Array.from(rowsByDay.keys()).sort((a, b) => {
  return (DAY_ORDER[a] || 99) - (DAY_ORDER[b] || 99);
});

let text = "";

text += "🍽 خلاصه خرید غذای کل هفته\n";

if (targetWeekStartJalali && targetWeekEndJalali) {
  text += `📅 بازه هفته: از ${targetWeekStartJalali} تا ${targetWeekEndJalali}\n`;
}

if (targetWeekStart) {
  text += `🗓 تاریخ شروع هفته میلادی: ${targetWeekStart}\n`;
}

text += "\n";

if (rows.length === 0) {
  text += "برای این هفته هیچ رزروی ثبت نشده است.\n";
} else {
  for (const day of sortedDays) {
    const dayRows = rowsByDay.get(day) || [];

    const dailyReservations = dayRows.reduce(
      (sum, row) => sum + row.people_count,
      0
    );

    const dailyPortionQty = dayRows.reduce(
      (sum, row) => sum + row.total_portion_qty,
      0
    );

    text += `📌 ${day} — ${dailyReservations} رزرو / ${formatQty(dailyPortionQty)} پرس معادل\n`;

    dayRows.forEach((row, index) => {
      text += `${index + 1}) ${row.food} - ${row.portion_label}: ${row.people_count} نفر / ${formatQty(row.total_portion_qty)} پرس\n`;
    });

    text += "\n";
  }
}

text += "━━━━━━━━━━━━━━\n";
text += `👥 تعداد کاربران یکتای هفته: ${weeklyUniqueUsers}\n`;
text += `🧾 مجموع رزروهای هفته: ${totalReservations}\n`;
text += `📦 مجموع پرس معادل هفته: ${formatQty(weeklyTotalPortionQty)}\n`;

return [
  {
    json: {
      text: text.trim(),
      target_week_start: targetWeekStart,
      target_week_start_jalali: targetWeekStartJalali,
      target_week_end: targetWeekEnd,
      target_week_end_jalali: targetWeekEndJalali,
      weekly_unique_users: weeklyUniqueUsers,
      total_reservations: totalReservations,
      weekly_total_portion_qty: weeklyTotalPortionQty,
    },
  },
];

const TEHRAN_TZ = "Asia/Tehran";
const CUTOFF_HOUR = 19;
const CUTOFF_MINUTE = 0;

function getTehranNowParts(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: TEHRAN_TZ,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hourCycle: "h23",
  }).formatToParts(date);

  const map = {};
  for (const part of parts) {
    map[part.type] = part.value;
  }

  return {
    year: Number(map.year),
    month: Number(map.month),
    day: Number(map.day),
    hour: Number(map.hour),
    minute: Number(map.minute),
    second: Number(map.second),
  };
}

function addDaysUtc(date, days) {
  const result = new Date(date);
  result.setUTCDate(result.getUTCDate() + days);
  return result;
}

function toIsoDate(date) {
  return date.toISOString().slice(0, 10);
}

function toPersianDigits(value) {
  return String(value).replace(/\d/g, (digit) => "۰۱۲۳۴۵۶۷۸۹"[digit]);
}

function toJalali(date) {
  const formatted = new Intl.DateTimeFormat("fa-IR-u-ca-persian", {
    timeZone: TEHRAN_TZ,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(date);

  return toPersianDigits(formatted);
}

const nowParts = getTehranNowParts();

const todayTehranAsUtcDate = new Date(Date.UTC(
  nowParts.year,
  nowParts.month - 1,
  nowParts.day
));

// JS day:
// Sunday=0, Monday=1, Tuesday=2, Wednesday=3, Thursday=4, Friday=5, Saturday=6
const jsDay = todayTehranAsUtcDate.getUTCDay();

// شنبه شروع هفته است
const daysSinceSaturday = (jsDay - 6 + 7) % 7;

const currentWeekStart = addDaysUtc(todayTehranAsUtcDate, -daysSinceSaturday);
const nextWeekStart = addDaysUtc(currentWeekStart, 7);

const isThursdayAfterCutoff =
  jsDay === 4 &&
  (
    nowParts.hour > CUTOFF_HOUR ||
    (nowParts.hour === CUTOFF_HOUR && nowParts.minute >= CUTOFF_MINUTE)
  );

const isFriday = jsDay === 5;

let targetWeekStart = currentWeekStart;
let reportWeekMode = "current_week";

if (isThursdayAfterCutoff || isFriday) {
  targetWeekStart = nextWeekStart;
  reportWeekMode = "next_week";
}

return [
  {
    json: {
      target_week_start: toIsoDate(targetWeekStart),
      target_week_start_jalali: toJalali(targetWeekStart),

      current_week_start: toIsoDate(currentWeekStart),
      current_week_start_jalali: toJalali(currentWeekStart),

      next_week_start: toIsoDate(nextWeekStart),
      next_week_start_jalali: toJalali(nextWeekStart),

      report_week_mode: reportWeekMode,
      tehran_weekday_js: jsDay,
      tehran_hour: nowParts.hour,
      tehran_minute: nowParts.minute,
    },
  },
];

const daysOrder = ['شنبه', 'یکشنبه', 'دوشنبه', 'سه شنبه', 'چهارشنبه', 'پنج شنبه'];

const weekMenu = $('Get Week Menu For Employees').all().map(i => i.json);
const reservations = $('Get User Weekly Reservations').all().map(i => i.json);
const targetWeekStart = $('Get Target Week Start').item.json.target_week_start;

const now = new Date();
const tehranNow = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Tehran' }));
const currentHour = tehranNow.getHours();

const jsDayToFa = ['یکشنبه', 'دوشنبه', 'سه شنبه', 'چهارشنبه', 'پنج شنبه', 'جمعه', 'شنبه'];
const todayFa = jsDayToFa[tehranNow.getDay()];

const dayIndexMap = {
  'شنبه': 0,
  'یکشنبه': 1,
  'دوشنبه': 2,
  'سه شنبه': 3,
  'چهارشنبه': 4,
  'پنج شنبه': 5,
  'جمعه': 6
};

const todayIndex = dayIndexMap[todayFa];

const dayMap = {
  0: 1, // Sunday -> یکشنبه
  1: 2, // Monday -> دوشنبه
  2: 3, // Tuesday -> سه شنبه
  3: 4, // Wednesday -> چهارشنبه
  4: 5, // Thursday -> پنج شنبه
  5: 6, // Friday -> جمعه
  6: 0  // Saturday -> شنبه
};

const currentFaDayIndex = dayMap[tehranNow.getDay()];

const startOfCurrentWeek = new Date(tehranNow);
startOfCurrentWeek.setDate(tehranNow.getDate() - currentFaDayIndex);
startOfCurrentWeek.setHours(0, 0, 0, 0);

const fmt = (d) => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const currentWeekStartStr = fmt(startOfCurrentWeek);
const isNextWeek = targetWeekStart !== currentWeekStartStr;

const menuMap = {};
for (const row of weekMenu) {
  menuMap[row.day_of_week] = row;
}

const reservationMap = {};
for (const row of reservations) {
  reservationMap[row.day_of_week] = row;
}

function getTomorrowFa() {
  const tomorrow = new Date(tehranNow);
  tomorrow.setDate(tomorrow.getDate() + 1);
  return jsDayToFa[tomorrow.getDay()];
}

function getDayStatus(day) {
  if (!menuMap[day]) {
    return 'no_menu';
  }

  if (isNextWeek) {
    return 'active';
  }

  const idx = dayIndexMap[day];
  const tomorrowFa = getTomorrowFa();

  if (idx < todayIndex) {
    return 'past';
  }

  if (idx === todayIndex) {
    return 'today';
  }

  if (day === tomorrowFa && currentHour >= 19) {
    return 'tomorrow_closed';
  }

  return 'active';
}

const rows = [];

for (const day of daysOrder) {
  const status = getDayStatus(day);
  const reserve = reservationMap[day];

  let text = day;
  let callback_data = `select_reserve_day|${day}`;

  if (status === 'past') {
    text = `⚪️ ${day} - گذشته`;
    callback_data = `ignore_day|${day}`;
  } else if (status === 'today') {
    text = `⛔️ ${day} - بسته`;
    callback_data = `ignore_day|${day}`;
  } else if (status === 'tomorrow_closed') {
    text = `⏰ ${day} - بسته`;
    callback_data = `ignore_day|${day}`;
  } else if (status === 'no_menu') {
    text = `📭 ${day} - بدون منو`;
    callback_data = `ignore_day|${day}`;
  } else {
    if (reserve) {
      text = `✅ ${day} - ${reserve.food} (${reserve.portion_label || 'پرس کامل'})`;
    } else {
      text = `🍽 ${day}`;
    }
  }

  rows.push([{ text, callback_data }]);
}

return [
  {
    json: {
      chat_id: $('Telegram Trigger').item.json.callback_query.message.chat.id,
      text: isNextWeek
        ? '🍽 رزرو غذای هفتگی (هفته بعد)\n\nلطفاً روز موردنظر را انتخاب کنید:'
        : '🍽 رزرو غذای هفتگی\n\nلطفاً روز موردنظر را انتخاب کنید:',
      reply_markup: {
        inline_keyboard: rows
      }
    }
  }
];

const menu = $('Get Selected Day Menu').first().json;
const reservation = $('Get Selected Day Reservation').first().json || {};
const day = menu.day_of_week;

const foodOptions = [
  { slot: 'f1', title: menu.food1 },
  { slot: 'f2', title: menu.food2 },
  { slot: 'f3', title: menu.food3 },
].filter((item) => item.title && String(item.title).trim());

const rows = foodOptions.map((item) => [
  {
    text: `🍽 ${item.title}`,
    callback_data: `choose_food_portion|${day}|${item.slot}`,
  },
]);

if (reservation.food) {
  rows.push([
    {
      text: '❌ لغو رزرو',
      callback_data: `cancel_reservation|${day}`,
    },
  ]);
}

rows.push([{ text: '🔙 بازگشت', callback_data: 'food_booking|menu' }]);

const currentReservationText = reservation.food
  ? `✅ رزرو فعلی شما: ${reservation.food}${reservation.portion_label ? ` - ${reservation.portion_label}` : ''}`
  : 'هنوز رزروی ثبت نشده است.';

const foodsText = foodOptions
  .map((item, index) => `${index + 1}️⃣ ${item.title}`)
  .join('\n');

return [
  {
    json: {
      chat_id: $('Telegram Trigger').item.json.callback_query.message.chat.id,
      text: `🍽 رزرو روز ${day}

لطفاً غذای موردنظر را انتخاب کنید:

${foodsText}

${currentReservationText}`,
      reply_markup: {
        inline_keyboard: rows,
      },
    },
  },
];

