function toJalaliDate(value) {
  if (!value) return '—';

  // اگر Postgres تاریخ را به شکل Date/ISO داده باشد، فقط بخش YYYY-MM-DD را نگه می‌داریم
  const raw = String(value);
  const datePart = raw.slice(0, 10); // 2026-05-09

  const [year, month, day] = datePart.split('-').map(Number);

  if (!year || !month || !day) {
    return raw;
  }

  // ساعت 12 UTC برای جلوگیری از جابه‌جایی روز به خاطر timezone
  const date = new Date(Date.UTC(year, month - 1, day, 12, 0, 0));

  return new Intl.DateTimeFormat('fa-IR-u-ca-persian', {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).format(date);
}

return items.map((item) => {
