];

const period = $('Code in JavaScript').item.json.value1;
const targetUserId = $('Code in JavaScript').item.json.value2;

const now = new Date();
const tehranNow = new Date(
  now.toLocaleString('en-US', { timeZone: 'Asia/Tehran' })
);

function startOfDay(date) {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate(), 0, 0, 0);
}

function addDays(date, days) {
  const next = new Date(date);
  next.setDate(next.getDate() + days);
  return next;
}

function startOfWeekSaturday(date) {
  const d = startOfDay(date);

  // JS: Sunday=0 ... Saturday=6
  const jsDay = d.getDay();

  // Persian week starts Saturday
  const daysSinceSaturday = (jsDay + 1) % 7;

  d.setDate(d.getDate() - daysSinceSaturday);
  return d;
}

function startOfMonth(date) {
  return new Date(date.getFullYear(), date.getMonth(), 1, 0, 0, 0);
}

let start;
let end;
let label;

if (period === 'daily') {
  start = startOfDay(tehranNow);
  end = addDays(start, 1);
  label = 'امروز';
} else if (period === 'weekly') {
  start = startOfWeekSaturday(tehranNow);
  end = addDays(start, 7);
  label = 'این هفته';
} else if (period === 'monthly') {
  start = startOfMonth(tehranNow);
  end = new Date(tehranNow.getFullYear(), tehranNow.getMonth() + 1, 1, 0, 0, 0);
  label = 'این ماه';
} else {
  start = startOfDay(tehranNow);
  end = addDays(start, 1);
  label = 'امروز';
}

return [
  {
    json: {
      target_user_id: targetUserId,
      period,
      period_label: label,
      start_ts: start.toISOString(),
      end_ts: end.toISOString(),
    },
  },
];

