const rows = $('Get Employee Status Duration Report').all().map(i => i.json);
const range = $('Build Report Range').item.json;

function cleanName(u) {
  const id = String(u.telegram_user_id || '').trim();
  const first = String(u.first_name || '').trim();
  let last = String(u.last_name || '').trim();

  if (last === id || /^[0-9]{5,}$/.test(last)) {
    last = '';
  }

  return [first, last].filter(Boolean).join(' ') || u.username || 'بدون نام';
}

function cleanUsername(u) {
  const username = String(u.username || '').trim();

  if (!username) {
    return 'ندارد';
  }

  return username.startsWith('@') ? username : `@${username}`;
}

function formatHours(value) {
  const n = Number(value || 0);

  if (!Number.isFinite(n) || n <= 0) {
    return '0';
  }

  if (Number.isInteger(n)) {
    return String(n);
  }

  return n.toFixed(2).replace(/\.?0+$/, '');
}

function toPersianDigits(value) {
  return String(value).replace(/\d/g, d => '۰۱۲۳۴۵۶۷۸۹'[Number(d)]);
}

function faDate(iso) {
  try {
    return new Intl.DateTimeFormat('fa-IR-u-ca-persian', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    }).format(new Date(iso));
  } catch {
    return iso;
  }
}

const base = rows[0] || {};
const name = cleanName(base);
const username = cleanUsername(base);
const department = base.department_title || '—';

let text = `📊 گزارش وضعیت کارمند\n\n`;
text += `👤 کارمند: ${name}\n`;
text += `تلگرام: ${username}\n`;
text += `تیم: ${department}\n`;
text += `بازه: ${range.period_label}\n`;
text += `محاسبه: فقط داخل ساعت کاری\n`;
text += `از ${faDate(range.start_ts)} تا ${faDate(range.end_ts)}\n\n`;

const validRows = rows.filter(r => r.status_code && Number(r.total_hours || 0) > 0);

if (!validRows.length) {
  text += 'برای این بازه گزارشی ثبت نشده است.';
} else {
  let total = 0;

  validRows.forEach((r, index) => {
    const parent = String(r.parent_status_title || '').trim();
    const child = String(r.status_title || '').trim();
    const status = parent && child
      ? `${parent} - ${child}`
      : child || parent || r.status_code;

    const hours = Number(r.total_hours || 0);
    total += hours;

    text += `${index + 1}) ${status}: ${formatHours(hours)} ساعت\n`;
  });

  text += `\nمجموع زمان ثبت‌شده: ${formatHours(total)} ساعت`;
}

return [
  {
    json: {
      chat_id: $('Telegram Trigger').item.json.callback_query.message.chat.id,
      text: toPersianDigits(text),
      reply_markup: {
        inline_keyboard: [
          [
            {
              text: 'بازگشت به انتخاب کارمند',
              callback_data: `status_employee_report_period|${range.period}|0`,
            },
          ],
          [
            {
              text: 'منوی وضعیت',
              callback_data: 'admin_status_menu|root',
            },
          ],
        ],
      },
    },
  },
];

